        request_id=request_id,
        mission_task_being_attempted=mission_task_being_attempted,
        mission_output_relative_paths=mission_output_relative_paths,
        requested_scope_topic=requested_scope_topic,
        requested_knowledge_id=requested_knowledge_id,
        selected_knowledge_id=selected_knowledge_id,
        policy_state=policy_state,
        decision_reason=policy_reason,
        local_knowledge_sufficient=local_knowledge_sufficient,
        indexed_knowledge_sufficient=indexed_knowledge_sufficient,
        external_requery_admissible=external_requery_admissible,
        operator_review_required=operator_review_required,
