                str(baseline["trusted_source_capability_need_path"]),
                str(baseline["trusted_source_reuse_decision_path"]),
                str(baseline["trusted_source_reuse_summary_path"]),
                str(baseline["trusted_source_knowledge_selection_path"]),
                str(baseline["trusted_source_requery_decision_path"]),
                str(baseline["trusted_source_reuse_vs_requery_path"]),
                str(baseline["trusted_source_knowledge_freshness_path"]),
                str(baseline["trusted_source_knowledge_reuse_readiness_path"]),
                str(baseline["trusted_source_capability_result_path"]),
                *list(policy_outputs.get("created_paths", [])),
